"""# 🧠 สร้างและตั้งค่าโมเดล Deep Learning (MobileNetV2)"""

import tensorflow as tf
from tensorflow.keras.applications import MobileNetV2
from tensorflow.keras.layers import Dense, Dropout, BatchNormalization, Input
from tensorflow.keras.models import Model
from tensorflow.keras.optimizers import Adam

# --- 1. โหลดโมเดล MobileNetV2 ---
base_model = MobileNetV2(
    input_shape=(224, 224, 3),
    include_top=False,
    alpha=1.0,
    weights='imagenet',
    pooling= 'max' # <--- ค่าโผล่มาเป็น 1D Vector เลย ไม่ต้อง Flatten
)

# --- 2. ปิดสมองส่วนต้น (Freeze Base) ---
base_model.trainable = False

# --- 3. ต่อหัวใหม่ให้โหดกว่าเดิม ---
x = base_model.output

# แทรกสมองส่วนกลางให้มันเรียนรู้ Pattern ใหม่ๆ ของรูป Malaria
x = Dense(128, activation='relu')(x)
x = BatchNormalization()(x) # <--- ช่วยให้มันเทรนได้สเถียรและเร็วขึ้น
x = Dropout(0.5)(x) # <--- อัดไป 0.5 เลย กันแม่งท่องจำข้อสอบ

predictions = Dense(2, activation='softmax')(x) # 2 คลาส: Normal, Malaria

# --- 4. รวมร่าง ---
model = Model(inputs=base_model.input, outputs=predictions)

# --- 5. ตั้งค่ากระบวนการเรียนรู้ (Compile) ---
# เปลี่ยน LR เป็น 0.001 ก่อน เพราะเราอัปเดตแค่หัวมัน ไม่ได้แตะ Base
model.compile(optimizer=Adam(learning_rate=0.00001),
              loss='categorical_crossentropy',
              metrics=['accuracy'])

print("✅ อัปเกรดโมเดลเสร็จแล้ว! ลุยเลยไอ้สัด!")
model.summary()

"""#🖼️ เตรียม Data Generator และการตั้งค่า Early Stopping"""

from tensorflow.keras.preprocessing.image import ImageDataGenerator
from tensorflow.keras.applications.mobilenet_v2 import preprocess_input
from tensorflow.keras.callbacks import EarlyStopping, ReduceLROnPlateau

# --- 1. เตรียมดูดรูป (Data Generator) อัปเกรดความโหด ---
train_datagen = ImageDataGenerator(
    preprocessing_function=preprocess_input,
    rotation_range=20,           # <--- เซลล์แม่งหมุนได้ ใส่ไปเลย 20 องศา
    shear_range=0.2,
    zoom_range=0.2,
    horizontal_flip=True,
    vertical_flip=True           # <--- พลิกบนล่างด้วย เม็ดเลือดไม่มีบนมีล่าง
)

validation_datagen = ImageDataGenerator(
    preprocessing_function=preprocess_input
)

# --- 2. สร้างตัวส่งข้อมูล (Generator) จาก DataFrame ---
train_generator = train_datagen.flow_from_dataframe(
    dataframe=train_df,
    x_col='filepath',
    y_col='label',
    target_size=(224, 224),
    batch_size=32,
    class_mode='categorical'
)

validation_generator = validation_datagen.flow_from_dataframe(
    dataframe=val_df,
    x_col='filepath',
    y_col='label',
    target_size=(224, 224),
    batch_size=32,
    class_mode='categorical',
    shuffle=False
)

# --- 3. ตั้งค่า Callbacks โคตรโกง ---
callbacks = [
    # หยุดเมื่อ Val_loss ไม่ลง 5 รอบติด แล้วดึงน้ำหนักที่ดีที่สุดกลับมา
    EarlyStopping(monitor='val_loss', patience=5, restore_best_weights=True),

    # ถ้า Val_loss ไม่ลง 3 รอบติด ให้หั่น Learning rate ทิ้งครึ่งนึง (0.5)
    ReduceLROnPlateau(monitor='val_loss', factor=0.5, patience=3, min_lr=1e-6, verbose=1)
]

# --- 4. สั่งรันเทรนโมเดล (มึงลืมส่วนนี้นะ) ---
print("🔥 เริ่มเทรนแล้วโว้ย ไปชงกาแฟรอได้เลย!")

"""#🚀 เริ่มขั้นตอนการฝึกสอนโมเดล (Model Training)"""

# --- 4. เข้า model.fit ---
EPOCHS = 30 # <---- จำนวนรอบในการ trainmodel ยิ่งเยอะยิ่งนาน เเนะนำ 10 ถึง 20

history = model.fit(
    train_generator,
    epochs=EPOCHS,
    validation_data=validation_generator,
    # callbacks=callbacks
)

print("🎉 เทรนเสร็จแล้ว!")

import matplotlib.pyplot as plt

def plot_history(history):
    acc = history.history['accuracy']
    val_acc = history.history['val_accuracy']
    loss = history.history['loss']
    val_loss = history.history['val_loss']

    epochs_range = range(len(acc))

    plt.figure(figsize=(12, 6))

    # กราฟ Accuracy
    plt.subplot(1, 2, 1)
    plt.plot(epochs_range, acc, label='Training Accuracy')
    plt.plot(epochs_range, val_acc, label='Validation Accuracy')
    plt.legend(loc='lower right')
    plt.title('Training and Validation Accuracy')

    # กราฟ Loss
    plt.subplot(1, 2, 2)
    plt.plot(epochs_range, loss, label='Training Loss')
    plt.plot(epochs_range, val_loss, label='Validation Loss')
    plt.legend(loc='upper right')
    plt.title('Training and Validation Loss')

    plt.show()

# เรียกใช้ฟังก์ชันซะ
plot_history(history)

"""# 📊 นำเข้า Library สำหรับประเมินผลและสร้าง Confusion Matrix ของชุดวัดผล"""

